import {
    GeneratedReportTemplate,
    IBaseReportTemplateCheck,
    IBaseReportTemplateData,
} from '@/modules/generated-report'

import { TLoanReleaseDetailSchema } from '../components/forms/loan-release-detail-create-report-form'
import LOAN_RELEASE_DETAIL_T1 from './templates/loan-release-detail-templates/ln-rls-detail-t1.njk?raw'

// START DO NOT EDIT
type TDataEntryItem = {
    passbook: string
    member_fullname: string

    cv_no: string
    release_date: string
    due_date: string
    firt_pay_date: string
    date_granted: string
    terms: string
    loan_type?: string
    maturity_date?: string
    mode_of_payment: string
    amortization: string | number
    amount_applied?: string | number
    interest_on_loan?: string | number
    amount_granted?: string | number

    rl?: string | number
    ccl?: string | number
    ml?: string | number
    cmkr?: string | number
    bod?: string | number
    cmc?: string | number
    legal?: string | number

    current?: string | number
    restructured?: string | number
    renewal?: string | number
}

export type TReportGroup = {
    // Gagamitin ko to solo nya <tr> indicator na start of its group
    roup_title: string
    group_name: string // examples -> Account, Member Type, Barangay etc..

    // If it has sub-groups (3+ levels), this is populated
    sub_groups?: TReportGroup[]
    //Pag leaf to, eto yung data nya meaning wlang sub group
    data_entries?: TDataEntryItem[]

    groupings?: TLoanReleaseDetailSchema['groupings']

    // seto din ididsplay based sa groupings set
    total_per: {
        total_amort?: string | number
        total_current?: string | number
        total_restuct?: string | number
        total_renewal?: string | number

        total_amount_applied?: string | number
        total_interest_on_loan?: string | number
        total_amount_granted?: string | number
    }
}

export interface ILoanReleaseDetailReportTemplate
    extends IBaseReportTemplateData, IBaseReportTemplateCheck {
    start_date: string
    end_date: string

    // attributes to populate sa TDataEntryItem, eto din ididisplay sa column based sa kung ano match nang grouping
    // eto didisplay sa nunjucks table LMAO

    // set 1 - pb no, member name, cv no, release date, due date, first pay, terms, paymode, amort, current, restruct, renewal

    // set 2 - pb no, member name, account name, cv no, release date, due date, first pay, terms, paymode, amort, current, restruct, renewal

    // set 3 - member name, loan type, date granted, terms, maturity date, payment mode, amount applied, interest on loan, amount granted

    // set 4 - pb no, member name, release date, due date, paymode, amort, granted, rl, ccl, ml, cmkr, bod, cmc, legal

    mode_of_payment?: TLoanReleaseDetailSchema['mode_of_payment']

    grouping: TLoanReleaseDetailSchema['groupings']
    /*
    "by_mtype_acct"  -> set 1
    "by_mtype_brgy"  -> set 2
    "by_mclass_area_mtype_grp"  -> set 3
    "by_coll_area"  -> set 2
    "by_mtype_mclass"  -> set 2
    "by_mtype_area"  -> set 3
    "by_mtype_acct_ltr"  -> set 4
    "by_mtype_ltype"  -> set 3
    "by_mtype_area_grp"  -> set 3
    "by_coll_brgy"  -> set 2
    "by_mtype_occup"  -> set 2
    "no_grouping" -> set 2
    */

    grouped_data?: TReportGroup[] // eto populate pag not no_grouping
    no_grouping_data_entries?: TDataEntryItem[] // eto populate mo if no_grouping

    // seto din ididsplay based sa groupings set
    grand_total: {
        total_amort?: string | number
        total_current?: string | number
        total_restruct?: string | number
        total_renewal?: string | number

        total_amount_applied?: string | number
        total_interest_on_loan?: string | number
        total_amount_granted?: string | number
    }

    // Signatures
    prepared_by?: string
    checked_by?: string
    approved_by?: string
}
// END DO NOT EDIT

